27	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
28	
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	
32	const CURSE_SURCHARGE_RATE = 0.5;
33	const FIRST_INSURANCE_RATE = 0.1;
34	const HIGH_ENCHANTMENT_RATE = 0.3;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const LOYALTY_DISCOUNT_RATE = 0.2;
37	const LOYALTY_YEARS_THRESHOLD = 2;
38	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
39	
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	
42	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
43	
44	const groupKeyFor = (item: Item, index: number): string =>
45	  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;
46	
47	const groupItemsForPricing = (items: Item[]): Item[][] => {
48	  const groups = new Map<string, Item[]>();
49	  items.forEach((item, index) => {
50	    const key = groupKeyFor(item, index);
51	    const group = groups.get(key) ?? [];
52	    group.push(item);
53	    groups.set(key, group);
54	  });
55	  return [...groups.values()];
56	};
57	
58	const premiumForGroup = (group: Item[]): number =>
59	  group.length === BLOCK_SIZE
60	    ? BLOCK_PREMIUM
61	    : group.reduce((total, item) => total + basePremiumFor(item), 0);
62	
63	const totalBasePremiumFor = (items: Item[]): number =>
64	  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);
65	
66	const itemSurchargeFor = (
67	  items: Item[],
68	  qualifies: (item: Item) => boolean,
69	  rate: number,
70	): number =>
71	  items.reduce(
72	    (total, item) => (qualifies(item) ? total + basePremiumFor(item) * rate : total),
73	    0,
74	  );
75	
76	const isCursed = (item: Item): boolean => item.cursed === true;
77	
78	const isHighlyEnchanted = (item: Item): boolean =>
79	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
80	
81	type QuoteContext = { customer: Customer; quoteIndex: number };
82	
83	type PolicyModifier = (base: number, items: Item[], context: QuoteContext) => number;
84	
85	const POLICY_MODIFIERS: PolicyModifier[] = [
86	  (_base, items) => itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE),
87	  (_base, items) => itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE),
88	  (base) => base * FIRST_INSURANCE_RATE,
89	  (base, _items, { customer }) =>
90	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -(base * LOYALTY_DISCOUNT_RATE) : 0,
91	  (base, _items, { quoteIndex }) =>
92	    quoteIndex > 0 ? -(base * FOLLOW_UP_DISCOUNT_RATE) : 0,
93	];
94	
95	const sumModifiers = (base: number, items: Item[], context: QuoteContext): number =>
96	  POLICY_MODIFIERS.reduce((total, modifier) => total + modifier(base, items, context), 0);
97	
98	const quotePremium = (items: Item[], context: QuoteContext): number => {
99	  const base = totalBasePremiumFor(items);
100	  return Math.ceil(base + sumModifiers(base, items, context) + PROCESSING_FEE);
101	};
102	
103	const processStep = ({ items = [] }: Step, context: QuoteContext): StepResult => ({
104	  premium: quotePremium(items, context),
105	});
106	
107	export const runScenario = (scenario: Scenario): ScenarioResult => ({
108	  results: scenario.steps.map((step, quoteIndex) =>
109	    processStep(step, { customer: scenario.customer, quoteIndex }),
110	  ),
111	});
